/**
 * 根据网络类型估算速度，动态计算最优分段时长
 */
private fun calculateOptimalSegmentDuration(): Long {
    try {
        val cm = context.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val network = cm.activeNetwork ?: return SEGMENT_DURATION
        val caps = cm.getNetworkCapabilities(network) ?: return SEGMENT_DURATION

        val upBandwidth = caps.linkUpstreamBandwidthKbps

        Log.d(TAG, "Network upstream bandwidth: ${upBandwidth}kbps")

        return when {
            upBandwidth > 8000 -> 600L   // >1MB/s: 10分钟
            upBandwidth > 4000 -> 480L   // >500KB/s: 8分钟
            upBandwidth > 1600 -> 360L   // >200KB/s: 6分钟
            else -> 300L                  // 慢速: 5分钟
        }
    } catch (e: Exception) {
        Log.w(TAG, "Failed to detect network speed, using default", e)
        return SEGMENT_DURATION
    }
}

